      `${config.method.toUpperCase()} :: ${config.baseURL}${config.url} --- headers :: ${JSON.stringify(
        filteredHeaders,
      )}`,
    );
    axiosLogger.info(`Call ${name} data ::`, { data: config.data, params: config.params });
