    (response: AxiosResponse) => {
      if (['post', 'delete', 'put'].includes(response.config.method ?? '')) {
        axiosLogger.info(`Calling client "${name}" success`, response.data);
      } else {
        axiosLogger.debug(`Calling client "${name}" success`, response.data);
      }
      return response.data;
    },
    (error: AxiosError<{ error: string }>) => {
      const { response, message } = error;
      if (response) {
