        axiosLogger.warn(`Calling client "${name}" failed message`, message);
        throw new ExternalApiError(response.data['message'] ?? response.data ?? message, response.status);
      } else {
        throw new ExternalApiError(`Cannot connect to client "${name}"`, 500);
      }
    },
  );

  return client;
};

