import { Body, JsonController, Post } from 'routing-controllers';
import { Service } from 'typedi';
import winston from 'winston';
import { ResponseSchema } from 'routing-controllers-openapi';

import { Logger } from '@Decorators/Logger';

import { env } from '@Libs/env';

import { WebhookEvent } from '@Enums/Webhook';

import { DynamicAPIKeyGuard } from '@Middlewares/guard/DynamicAPIKeyGuard';

import { ErrorCode } from '@Errors/ErrorCode';

import { HotelService } from '@Services/HotelService';

import { WebhookDto } from '@Rests/types/WebhookDto';

@Service()
@JsonController('/webhook')
export class WebhookController {
  constructor(@Logger(module) private readonly logger: winston.Logger, private readonly hotelService: HotelService) {}

  @DynamicAPIKeyGuard(env.webhook.hotel.apikey)
  @Post('/hotel')
  @ResponseSchema(String)
  async webhookHotel(@Body() body: WebhookDto) {
    switch (body.event) {
      case WebhookEvent.HOTEL_BOOKING_EXPIRED:
        return this.hotelService.expiredBooking(body.payload.bookings);
      case WebhookEvent.HOTEL_BOOKING_CHECKIN_REMINDER_SENT:
        return this.hotelService.sendCheckinReminder(body.payload.bookings);
      case WebhookEvent.HOTEL_BOOKING_CHECKED_OUT:
        return this.hotelService.sendCheckedOut(body.payload.bookings);

      default:
        throw new Error(ErrorCode.INVALID_WEBHOOK_EVENT);
    }
  }
}

